DROP TABLE IF EXISTS ORDER_ITEM;
DROP TABLE IF EXISTS ORDERS;
DROP TABLE IF EXISTS CUSTOMER;

DROP SEQUENCE IF EXISTS CUSTOMER_SEQ;
DROP SEQUENCE IF EXISTS ORDERS_SEQ;
DROP SEQUENCE IF EXISTS ORDER_ITEM_SEQ;

CREATE SEQUENCE CUSTOMER_SEQ START WITH 10 INCREMENT BY 1;
CREATE SEQUENCE ORDERS_SEQ START WITH 10 INCREMENT BY 1;
CREATE SEQUENCE ORDER_ITEM_SEQ START WITH 10 INCREMENT BY 1;

-- ID BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
-- ID BIGINT DEFAULT NEXT VALUE FOR CUSTOMER_SEQ PRIMARY KEY,
-- id BIGINT GENERATED ALWAYS AS IDENTITY (START WITH 10 INCREMENT BY 1) PRIMARY KEY

CREATE TABLE CUSTOMER
(
    ID          BIGINT          PRIMARY KEY,
    CUSTOMER_NO VARCHAR(20)     NOT NULL UNIQUE,
    NAME        VARCHAR(200)    NOT NULL,
    EMAIL       VARCHAR(255),
    CREATED_AT  TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP
);

COMMENT ON TABLE CUSTOMER IS 'Table for Customers';
COMMENT ON COLUMN CUSTOMER.ID IS 'PrimaryKey';
COMMENT ON COLUMN CUSTOMER.CUSTOMER_NO IS 'Number of Customer';
COMMENT ON COLUMN CUSTOMER.NAME IS 'Name of Customer';
COMMENT ON COLUMN CUSTOMER.EMAIL IS 'Mail of Customer';
COMMENT ON COLUMN CUSTOMER.CREATED_AT IS 'Creation Timestamp of Customer';

CREATE TABLE ORDERS
(
    ID          BIGINT      PRIMARY KEY,
    CUSTOMER_ID BIGINT      NOT NULL,
    ORDER_NO    VARCHAR(30) NOT NULL UNIQUE,
    ORDER_DATE  DATE        NOT NULL DEFAULT CURRENT_DATE,
    STATUS      VARCHAR(20) NOT NULL DEFAULT 'NEW',

    CONSTRAINT FK_ORDERS_CUSTOMER FOREIGN KEY (CUSTOMER_ID) REFERENCES CUSTOMER (ID) ON DELETE RESTRICT ON UPDATE RESTRICT
);

CREATE INDEX IF NOT EXISTS IX_ORDERS_CUSTOMER_ID ON ORDERS (CUSTOMER_ID);

CREATE TABLE ORDER_ITEM
(
    ID              BIGINT          PRIMARY KEY,
    ORDER_ID        BIGINT          NOT NULL,
    POSITION_NO     INT             NOT NULL,
    PRODUCT_CODE    VARCHAR(50)     NOT NULL,
    QUANTITY        INT             NOT NULL CHECK (QUANTITY > 0),
    UNIT_PRICE      DECIMAL(12, 2)  NOT NULL CHECK (UNIT_PRICE >= 0),

    CONSTRAINT FK_ORDERITEM_ORDERS FOREIGN KEY (ORDER_ID) REFERENCES ORDERS (ID) ON DELETE CASCADE ON UPDATE RESTRICT,
    CONSTRAINT UQ_ORDERITEM_ORDER_POS UNIQUE (ORDER_ID, POSITION_NO)
);

CREATE INDEX IF NOT EXISTS IX_ORDERITEM_ORDER_ID ON ORDER_ITEM (ORDER_ID);
